update private_msg
set is_read = 1
where tar_user_id = #{userId}
  and src_user_id = #{peerId}
  and is_read = 0
  and tar_deleted = 0

update private_msg
set is_read = 0
where id = (
    select id from (
        select pm.id
        from private_msg pm
        where pm.src_user_id = #{peerId}
          and pm.tar_user_id = #{userId}
          and pm.tar_deleted = 0
        order by pm.msg_time desc, pm.id desc
        limit 1
    ) x
)

update private_msg
set tar_deleted = 1
where tar_user_id = #{userId}
  and src_user_id = #{peerId}

update private_msg
set src_deleted = 1
where src_user_id = #{userId}
  and tar_user_id = #{peerId}

